const input = $json;
const payload = input.body ?? input;
const body = typeof payload === 'string' ? JSON.parse(payload) : payload;
const search = body.search ?? {};
const callback = body.callback ?? {};
const query = String(search.queryTemplate ?? '').trim();
if (!query) {
  throw new Error('search.queryTemplate is required');
}
if (!body.executeAtUtc) {
  throw new Error('executeAtUtc is required');
}
if (!callback.url || !callback.token) {
  throw new Error('callback.url and callback.token are required');
}
const requestedCount = Number(search.count ?? 5);
const count = Number.isFinite(requestedCount) && requestedCount > 0
  ? Math.min(Math.trunc(requestedCount), 20)
  : 5;
const queryParts = [];
const appendQuery = (name, value, transform = (text) => text) => {
  const text = String(value ?? '').trim();
  if (!text || ['null', 'undefined'].includes(text.toLowerCase())) {
    return;
  }
  queryParts.push(`${name}=${encodeURIComponent(transform(text))}`);
};
appendQuery('q', query);
appendQuery('count', count);
appendQuery('country', search.country, (text) => text.toUpperCase());
appendQuery('search_lang', search.searchLang, (text) => text.toLowerCase());
appendQuery('freshness', search.freshness);
const braveSearchUrl = `https://api.search.brave.com/res/v1/web/search?${queryParts.join('&')}`;
return [{ json: {
  ...body,
  search: {
    queryTemplate: query,
    country: search.country ?? null,
    searchLang: search.searchLang ?? null,
    count,
    freshness: search.freshness ?? null,
    braveSearchUrl
  },
  callback
} }];

const response = $json;
const context = $('Prepare Job Context').first().json;
const results = (response.web?.results ?? []).slice(0, Number(context.search.count ?? 5)).map((item) => ({
  title: item.title ?? null,
  url: item.url ?? item.profile?.url ?? null,
  description: item.description ?? item.snippet ?? null,
  source: item.meta_url?.hostname ?? item.profile?.name ?? null
}));
const llmContext = results
  .map((item, index) => `${index + 1}. ${item.title ?? 'Untitled'}\n${item.url ?? ''}\n${item.description ?? ''}`.trim())
  .join('\n\n');
return [{ json: {
  callbackUrl: context.callback.url,
  callbackToken: context.callback.token,
  jobId: context.jobId,
  scheduleId: context.scheduleId,
  query: context.search.queryTemplate,
  retrievedAtUtc: new Date().toISOString(),
  results,
  llmContext,
  correlationId: context.jobId,
  attemptNumber: 1
} }];
